import{V as e,et as t,mt as n,tt as r}from"./chunks/framework.DpI_zlPE.js";var i=JSON.parse(`{"title":"diy桌游","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/自扫自印/diy桌游.md","filePath":"ccc/自扫自印/diy桌游.md"}`),a={name:`ccc/自扫自印/diy桌游.md`};function o(e,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[r(`<h1 id="diy桌游" tabindex="-1">diy桌游 <a class="header-anchor" href="#diy桌游" aria-label="Permalink to “diy桌游”">​</a></h1><h2 id="制图" tabindex="-1">制图 <a class="header-anchor" href="#制图" aria-label="Permalink to “制图”">​</a></h2><p><a href="https://sgs.miscity.cn:20081" target="_blank" rel="noreferrer">diy三国杀网页制图工具</a>；<a href="https://pandagm.com/tools/" target="_blank" rel="noreferrer">Panda提供的设计指南，范例，工具</a>；<a href="https://space.bilibili.com/9661652" target="_blank" rel="noreferrer">zyydi制图教程</a>；</p><p><a href="https://pan.baidu.com/s/1157YMU_3r-lmIhKt1RKNjQ?pwd=bxzz" target="_blank" rel="noreferrer">百度网盘</a></p><blockquote><p>附indesign模板，可用于HP indigo彩印，配有批处理辅助脚本和演示视频。</p><p>附PS自动生成出血的动作，圆角卡图补齐直角的动作，可用PS自动批处理。另有topazAI软件，可用于超分辨率卡图，支持cpu。</p><p>AI扩图，对文本框，边框的处理暂时不理想，只适合扩图原画出血。尝试用<a href="https://space.bilibili.com/12566101" target="_blank" rel="noreferrer">秋葉aaaki</a>的comfyui整合包，网盘转载两个工作流。用comfyui整合包的节点管理器修复缺失的节点。</p></blockquote><p>200多块买台重型冲卡器即可自印，网友用拼740x510mm大版模板，同城HP indigo数码印刷机300g铜版纸双面彩印覆膜，8￥，可冲55张卡，折合单价1毛5。</p><p>自己冲卡，牌面出血可以每边只留0.5mm，冲卡时用白边大小作为参照确保不歪斜然后平移消弭白边，再冲卡。出血留的小，最歪也不过1~2°左右，基本感知不到，再歪就会露白。</p><p>外面做卡，出血基本要每边1~2mm。</p><p><strong>INDIGO最好覆膜，不然指甲一抠就能抠下来。</strong></p><p>据网友风信子反馈小字存在明显的笔画断裂现象，不过<strong>文字辨识度不成问题</strong>。凑近了细看能察觉有印刷网纹，原画看起来不够细腻。后文INDIGO章节附图。</p><p><strong>网友反馈，霜X有类似的一模一样的笔画断裂现象，对比之下推测可能是indigo12000或更老的机型，anyway</strong>。</p><p>据网友风信子反馈hp 12000及更早机型上比较容易感知印刷网纹，而相对比较新的的hp 15k要细腻一些，相对更不易感知网纹，笔画断裂现象也有改善，他正在寻找HP 18K <strong>HD</strong>机型，希望HD机型能够让他满意。</p><p>我推测原因<strong>可能是图文快印商家的质量设置为速度优先。</strong>图文快印商家的indigo自印解决的是DIY桌游来玩，而不是说追求一个艺术上的收藏品。后文indigo彩印有进一步分析介绍。</p><p>愿意自己冲卡，<strong>我喷墨单打印</strong>鱼“不晓自在”，A4-300g铜版纸，6色天威成膜染料，双面1块。有褪色风险，关键是避光。无保护避光保存的耐候性测试中。包邮折扣那些照旧，我还是建议indigo自印，好赖是颜料。</p><p>另有10色微喷颜料单面打印，打在A4/A3相纸，不切卡入册，或自己DIY设定集、画册等。</p><p>画册、影集不推荐市面上一切胶装，热熔胶寿命就几年，都不用翻来翻去，自己放着就会老化脱胶。省力的话，插页资料册。</p><p>DIY的话，买一本中国摄影之类的影集看看蝴蝶装的样子，用书边带+无酸白胶粘书脊，用一个大夹子夹住，有书边带要牢靠非常多，即使运气不好脱胶了，自己修补也非常方便。或干脆全部摊开来放在无酸档案盒。</p><p><strong>桌游代工厂</strong>有商家54张x10份这样的数量就能做，单价可能在5毛/卡左右。</p><h3 id="硬挺度" tabindex="-1">硬挺度 <a class="header-anchor" href="#硬挺度" aria-label="Permalink to “硬挺度”">​</a></h3><p>官正诸如珍藏版典藏版那些之所以更硬挺，是因为涂布了上光浆料，会放硬挺剂，所以350g相对DIY的300g纸张硬挺很多，DIY想要实现较高的硬挺度，可行的方法是覆加厚的PET膜，不过据z佬说观感会更暗。</p><h2 id="切卡" tabindex="-1">切卡 <a class="header-anchor" href="#切卡" aria-label="Permalink to “切卡”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>三国杀：62x87mm-R3mm</span></span>
<span class="line"><span>标准扑克尺寸： 63.5x88.9mm，（2.5寸x3.5寸）</span></span>
<span class="line"><span>有一些网站标注万智是63.5x88.9mm，但据老外分享，DIY做63x88mm正好。</span></span></code></pre></div><ul><li><p>铡刀型切纸刀+省力型倒角钳，成本低，就是费事，而且往往明显尺寸不一。</p></li><li><p>定制重型冲卡机， <a href="https://shop104152472.taobao.com/" target="_blank" rel="noreferrer">淘宝·印后 相册 广告设备专销店</a>，是我找到报价最低的，200+12邮费，可能还有更便宜的。</p></li></ul><p>重型冲卡机，出血留大了目视对齐容易歪斜，想要避免歪斜，目视对齐的一面出血要小，靠白边的大小来判断是否歪斜，然后平移消弭白边。缺点是要注意力集中，也是比较费事的。</p><ul><li>定制电动名片切卡机+手动圆角机成本900+200，机器不算很大。相对省力很多，主要是不需要集中注意力。</li></ul><p>小型机器只能切不覆膜的350g纸。切出来是直角，需要手动圆角机切圆角，由于R3圆角太小，稍微有点误差视觉上会比较明显，主要表现是倒角不对称。</p><blockquote><p>切卡机最好搭配印刷彩印。只能切不覆膜的纸张，喷墨自印必须要颜料墨水保证耐候性，搭配颜料墨水可以不覆膜的纸张表现力会差一些。</p></blockquote><ul><li>电动压痕机700~800左右，把划线刀换成切割刀，客服说可以切割覆膜350g纸。</li></ul><p>客服说能切的机器基本有460mm宽，占地面积很大，而且要横切一刀再竖切一刀，就一台机器要重调刀具位置，想省力一点的话可能要弄两台机器。</p><ul><li><p>能切覆膜纸的电动切卡机，一次进纸完成切卡，定制7.8K，阿里巴巴“广州缔森机电设备有限公司”。</p></li><li><p>2~3万左右定制的自动冲卡机，人工上料，需要人工对准1个激光参考锚点，冲卡是倒好角的，机器占地面积很大。闲鱼用户“光信制卡厂”。</p></li><li><p>印刷厂用模切机</p></li></ul><p>核心原理是刀模，然后机器施加压力，有直上直下的，有滚筒施加压力的。进纸有人工上料对准的，有人工上料后自动对准的，有自动上料的。</p><p>搜索关键词：扑克自动冲卡机，早教卡自动冲卡机。</p><p>扑克牌印刷厂看视频有些先切成出血大小，然后叠一起用同一个模具模切，不知道是不是为了一致性。</p><p>搜索关键词：商标液压模切机</p><h2 id="indigo彩印" tabindex="-1">INDIGO彩印 <a class="header-anchor" href="#indigo彩印" aria-label="Permalink to “INDIGO彩印”">​</a></h2><p>参考前文自行切卡，既印刷又切卡往往收费不菲，只印刷便宜很多。</p><p>网友用拼740x510mm大版模板，找同城HP indigo数码印刷机300g铜版纸双面彩印覆膜，8块，可冲55张卡，折合单价1毛5。</p><p><strong>INDIGO最好覆膜，不然指甲一扣就能扣下来。</strong></p><p>商家的覆膜机很多是液压的，比diy的小型机覆膜牢靠。<strong>indigo机器自带密度仪</strong>，自带校色，<strong>能保证下限</strong>。缺点是线上要一定量才能摊低价格，邮费一般按顺丰收，比较高。</p><p>线下找可以试试抖音上搜，或搜招indigo操作员的公司。</p><p>indigo原理是液体电子油墨在橡皮布加热转印成膜，这个过程免不了墨点可能流动，看起来会有点肉是正常现象。</p><p>从群友风信子返图来看，<strong>小字存在明显的笔画断裂现象</strong>，不过<strong>文字辨识度不成问题</strong>。凑近了细看能察觉有印刷网纹，原画看起来不够细腻。</p><p><strong>网友反馈，霜X有类似的一模一样的笔画断裂现象，对比之下推测可能是indigo12000或更老的机型，anyway</strong>。</p><p>据网友风信子反馈hp 12000及更早机型上比较容易感知印刷网纹，而相对比较新的的hp 15k要细腻一些，相对更不易感知网纹，笔画断裂现象也有改善，他正在寻找HP 18K <strong>HD</strong>机型，希望HD机型能够让他满意。</p><p><strong>我推测可能是图文快印商家的质量设置为速度优先。</strong></p><p>市场很现实，报价低的图文快印商家基本都在内卷打价格战，往往是多年机龄的老机器，第三方维保，机器能跑起来就行，对效果都是非常凑合。</p><p>如果要更好的效果可能要找那些用indigo做影集，画册的商家，并确认其打印质量设置开的是最高档，但价格就不是贵一点点了，或干脆压根不接小单。indigo质量开高点效果应该还可以，如正印坊的定制自称就是indigo4色。</p><p>通常工业生产的规律就决定了需要足够单量来摊薄成本，而DIY自印卡太小众，只能蹭。如果对广告图文快印商家的品质不满意，考虑蹭包装印刷的商家，其中不乏有G7认证，至少有色彩管理操作经验，实际不一定严格色彩管理，但要求做ICC是可以做的。<strong>不过往往报价会贵很多。</strong></p><p><strong>商家都不老实，相当一部分实际是嘴巴选手，老旧机器+兼容油墨，但是往往牛逼吹得震天响，报价又高，真的是很恶心。</strong></p><blockquote><p>被我逮捕的一个嘴巴选手：晨曦印刷厂（宿迁盛晨趣商贸有限公司）。</p></blockquote><p>淘宝·皓玥书印装帧定制，indigo12000六色（CMYK+LC+LM）有白墨，可能可以印PVC之类的，能做ICC。</p><p><strong>澜达印刷机</strong>是HP indigo的发明人最新力作，同样通过橡皮布转印，但indigo是类似于激光打印机的静电吸附颗粒成像，而Landa则是喷墨成膜转印。相对喷墨兼容颜料应该明显改善界面反射率差异引起的颜料烫金效应，据Landa介绍，其墨水D50粒径约50nm，性能相当不俗，颜料颗粒的粒径过大可能会影响雾度，导致其看起来发灰。应该说Landa品质上应该接近喷墨水平，尤其是选配所谓PrintAI模块号称达到1200x1200dpi，完全是爱普生级别的喷墨水平。但是由于种种原因，澜达公司目前正在破产重组，此前上海丽邱源、河南盛大买了机器，但是好像没有拉过来安装。</p><p>图文快印INDIGO小字笔画断裂：</p><p><img src="https://s2.loli.net/2025/10/18/fm7xKQaqJTMkpCZ.jpg" alt=".jpg"></p><p>左INDIGO右喷墨，这家INDIGO相对烂一点：</p><p><img src="https://s2.loli.net/2025/10/18/8yzmvLM9wcdYenR.jpg" alt="-.jpg"></p><p>左INDIGO右喷墨，这家INDIGO相对好一点：</p><p><img src="https://s2.loli.net/2025/10/18/cdEFzBXH41UgbD5.jpg" alt="-.jpg"></p><p><strong>除了indigo彩印，其他数码印刷方式介绍：</strong></p><p>会做色彩管理的，往往定位较高，比如艺术微喷，要价不菲。</p><p>价格实惠的基本只有图文广告市场的商家，一般都不做色彩管理，需要设备保证下限。</p><p>激光碳粉机，大面积堆色会掉粉，还不好做色彩管理，碳粉随着使用会变。输出往往含硅油，覆膜不是最牢靠。</p><p>小图文店喷墨打印机如果用白卡纸，表现力受限。如果用喷墨铜版纸有报价实惠的，可以考虑参考<a href="https://zhuanlan.zhihu.com/p/2024923980432250737" target="_blank" rel="noreferrer">相机翻拍校色打印机</a>。</p><p><strong>喷墨打印机不是一次进纸双面打印，往往正反面位置有偏差，自己的机器还能调模板，外面打印就比较麻烦了。</strong></p><p>喷墨+铜版纸专用颜料墨水的<strong>数码印刷机</strong>（和打印机区分）已经面世，可能未来会有商家导入这样的机器。这种大机器一般都能保证下限。</p><blockquote><p>喷墨高光铜版纸涂布有喷墨涂层吸墨。印刷铜版纸准确来说叫印刷涂布纸，搭配的铜版纸专用颜料墨水不需要喷墨涂层就也可以打印。</p></blockquote><h2 id="diy打印双面对齐" tabindex="-1">DIY打印双面对齐 <a class="header-anchor" href="#diy打印双面对齐" aria-label="Permalink to “DIY打印双面对齐”">​</a></h2><p>软件用Indesign，排好版，链接图片，让内容缩放适配框架。打印机上限纸器装纸以后推紧。打印测试用尺量偏移再微调模板文件，我一般牌面文件固定，微调牌背的文件。</p><p>通常纸张纵向和横向的硬挺度不一样，一般纵向上会相对更硬挺一点，所以一般A4最好3x3排列。</p><h2 id="覆膜·塑封" tabindex="-1">覆膜·塑封 <a class="header-anchor" href="#覆膜·塑封" aria-label="Permalink to “覆膜·塑封”">​</a></h2><ul><li>冷裱膜是pvc，特别厚，而且很软，手感像套了个手机软壳。</li><li>覆膜（热裱膜）普通bopp预涂膜不防刮，指甲可以划出白痕，有些膜不顺滑。 <ul><li>光膜是镜面反射，会成像，和原卡差异较大。</li><li>哑膜几乎没有反光，同原卡有差异。</li><li>防刮BOPP哑膜手感会有一点粘腻，会有一点新的银行卡上面贴的保护膜那种感觉，没有质感。</li><li>阿里巴巴天宝印刷，一款21柔光膜，一款微米30哑膜。光泽度介于哑膜亮膜之间，柔光膜会成像偏漫反射，观感和过光油原卡相对接近些。哑膜则是有一定光泽度的漫反射，相对比较接近覆膜原卡。</li><li><strong>DIY建议PET哑膜，可以改善走纸印和棘轮印。</strong>相对稍微更硬挺点，也不怕刮。</li><li>淘宝 艺都千帆塑封工厂，直接联系客服买PET哑膜。有加厚的，更硬挺。不过据z佬说观感会更暗。</li></ul></li><li><strong>印刷厂液压覆膜压力大，还会过压纹机，切割后还是很服帖，diy覆膜可能翘边，起膜。</strong></li><li>印刷厂过压纹机可以做凹凸手感和纹路；diy定制十字布纹预涂膜，只有纹理没有凹凸手感。</li></ul><p>小型台式覆膜机，新机器看看淘宝同一数码科技的机器便宜点。没有液压机劲大，<strong>尽量买可以调速的，可以把速度调慢点来改善效果。</strong></p><h3 id="塑封膜" tabindex="-1">塑封膜 <a class="header-anchor" href="#塑封膜" aria-label="Permalink to “塑封膜”">​</a></h3><ul><li><p>无论是覆膜还是塑封，都是热熔胶合膜层和打印面，开胶撕掉会把打印的图案撕走。</p><blockquote><p>我定制了【72x99】10丝在售，用于【无损塑封】，既套牌套塑封，牌套的封口对准塑封膜的封口。卡牌可以无损拆出，但是可能有气泡，拿在手里，或轻捏卡牌都能明显感知到有空洞感，牌和牌套之间是空的，而牌套已经黏住塑封膜。</p></blockquote></li><li><p>塑封膜不足8丝留边像照片纸的硬度，10丝更硬一点，8丝折中。</p><ul><li>商家塑封套餐一般用6~8丝。</li></ul></li><li><p>推荐大厂艺都千帆定制（淘宝或阿里巴巴），10包起订，算上邮费，10丝7块多一包，8丝5块多一包。</p></li></ul><blockquote><p>大厂倒角圆润，热熔胶涂布均匀，收缩率低，透明度高。</p></blockquote><ol><li>把卡牌推到封边底，塑封后约4mm留边。</li><li>封短边则上下留边居中比较稳定，左右目视对齐，无法避免偏差。封长边则左右留边比较稳定，我更倾向于封长边。</li><li>塑封膜外径主要影响留边边距，我定制一般四边都留边4mm。</li><li>三国杀官正出血四边都是2~3mm，所以我倾向于留边四边一致。</li><li>通常留边至少3mm，但有一边是目视对齐，稳妥起见预留7mm，避免误差，留8mm。</li></ol><p>三国杀卡牌【62x87】，St尺寸（万智）【63x88】。我会定制三国杀【70x95】，St【71x96】。</p><h3 id="塑封机" tabindex="-1">塑封机 <a class="header-anchor" href="#塑封机" aria-label="Permalink to “塑封机”">​</a></h3><p>几十块塑料壳的塑封机只有两个辊不如铁壳的4辊平整。</p><p>加热方式分为石英管和云母片，石英管是红外灯管。石英管分为内加热和外加热，云母片暂时只有外加热，内加热是把加热管装在胶辊里。外加热是加热管在胶辊旁边加热胶辊。</p><ul><li><p>内加热更均匀，但是加热速度慢，胶辊贵。</p></li><li><p>云母片加热速度快，预热时间短，传热效率高，连续作业效果好，但是成本高。</p><ul><li><p>200￥雷盛LM320-S(T)内加热，塑料齿轮，19mm胶辊。</p></li><li><p>350￥平达330C，云母片，金属齿轮（跟客服要云母片的）。</p></li><li><p>500￥平达330CN是内加热，金属齿轮，25mm胶辊。</p></li><li><p>720￥平达330TD，云母片+可调高速，适合量很大。</p></li></ul></li></ul><p>量小不在乎速度慢尽量买内加热，量大尽量买云母片+可调高速，石英管外加热温度不均匀，容易出瑕疵。</p><p>塑封机并不是绿灯亮了就可以塑封了，绿灯亮只代表温度传感器检测的点达到设定温度，并不代表整根胶辊的温度都够了。所以使用中可以考虑先调到80~90度，绿灯亮起后预热5分钟左右，再调到需要的温度，再次亮起再酌情开始塑封。温度尽量不要猛猛调高。</p><h3 id="常见塑封异常" tabindex="-1">常见塑封异常 <a class="header-anchor" href="#常见塑封异常" aria-label="Permalink to “常见塑封异常”">​</a></h3><p>雾状白点，不粘，温度不够（设定过低或胶辊温度不均匀或绿灯没亮）。</p><p>泡点（一点一点，点之间有一定间距）温度过高或胶辊需要清洁。</p><p>起皱不平整，温度过高或放置不平整。</p><p>留边不粘或起泡（类似于手机贴膜有气泡），温度不够或胶辊压力不够，有两个有弹簧的螺丝拧一下。</p><h2 id="打印机" tabindex="-1">打印机 <a class="header-anchor" href="#打印机" aria-label="Permalink to “打印机”">​</a></h2><p><strong>喷墨打印前要进行输出锐化</strong>，qimage ultimate软件打印的自带锐化对白字的处理比较好。PS下可以用pixelgenius的PK滤镜，这个输出锐化滤镜是识别高对比反差，白字描黑反而劣化效果。网盘-软件内有。</p><p>家用打印机都是RGB打印机，驱动接收RGB编码，<strong>不需要改成CMYK</strong>。由喷墨程序将RGB编码转换为CMYK喷墨量。要效果好应进行色彩管理，<a href="https://www.bilibili.com/video/BV1gFSCYqE5w" target="_blank" rel="noreferrer">请参考</a>用扫描仪校色打印机。</p><blockquote><p>印刷厂如胶印是CMYK四色油墨分别刷一遍，调整CMYK通道可以优化效果，比如把四色黑改成单色黑可以避免重影。</p></blockquote><ul><li>原装颜料太久不打都可能堵死喷头，清洗清不通，至少每周打一次可以是喷头检查图。</li><li>颜料色稳定，不褪色，色准高，但可能有凹凸感（高光纸表面明显墨水颗粒的痕迹）。</li><li>由于光线漫射反光会产生烫金效应，反光泛白，泛青铜色，观感怪异。尤其是C、LC墨水以及CMY混合而成的灰阶。</li><li><strong>但是对于自印没有特别合适的纸张，详见后文。</strong>但颜料的耐候性摆在那里，所以也可以硬着头皮上颜料。</li><li>---</li><li>染料就算是兼容墨水都不会堵死，断线基本是打印头干了，清洗能清通。但<strong>会褪色</strong>，需要避光保存。<strong>覆膜或塑封可以明显改善耐候性。</strong></li><li>染料观感更吸睛，饱和度高，色彩还原能力更好，不存在光线漫射。具有通透感，亮光感是颜料无法实现的。</li></ul><h3 id="打印机-1" tabindex="-1">打印机 <a class="header-anchor" href="#打印机-1" aria-label="Permalink to “打印机”">​</a></h3><p>  <strong>打300克铜版纸，厚纸必须后进纸。</strong>如果打印头蹭纸，可以尝试在设置中勾选“厚纸与信封纸”。</p><p>据wilhelm-research实测加数学推测，标准可能是某个墨水的色密度衰减35%，<a href="https://zhuanlan.zhihu.com/p/1911928560123351144" target="_blank" rel="noreferrer">避光无保护的测试进行中</a>：</p><p><strong>据我测试，兼容染料无保护避光保存，约半年灰平衡被破坏，数学推测约5年将严重褪色。</strong>覆膜或塑封可以改善耐候性，但是热熔胶寿命受限，过个5，6年，可能热熔胶自己开始脱胶了。如果对色彩要求严格，覆膜或塑封后，实际上也还是在缓缓褪色。</p><table tabindex="0"><thead><tr><th></th><th>隔绝空气室内光照展示</th><th>室内敞开展示</th><th>无保护避光</th></tr></thead><tbody><tr><td>颜料墨水</td><td>60~200年</td><td>60~200年</td><td></td></tr><tr><td>干扩机染料014(L8168)，D580</td><td>98年</td><td>14年</td><td></td></tr><tr><td>爱普生6色原装染料（T674）（056?）</td><td>17年</td><td>半年</td><td></td></tr><tr><td>爱普生4色原装染料</td><td>4~5年</td><td>1周</td><td></td></tr><tr><td>兼容耐光染料</td><td></td><td>4~5周（我测试）</td><td></td></tr><tr><td>兼容成膜染料（天威R330<strong>影像级</strong>）</td><td></td><td>测试中，数学推测3~4个月（我测试）</td><td></td></tr></tbody></table><ul><li><strong>各家原装墨水除了提到的墨水外都不要考虑</strong>，耐候性都是兼容抗UV染料的水平，对不起价格。</li><li>佳能G580的原装墨水GI-83是chromalife100墨水，彩色耐候性接近干扩机染料，但是黑色耐候性拖了后腿，只是同爱普生6色原厂染料相近。</li><li>A4单面打印，爱普生机型通常共消耗墨水约0.75ml左右，佳能热发泡可能会多消耗一些。</li><li>爱普生大幅面染料抽墨，活的色彩DS6、NDD耐候性同兼容耐光染料差不多。</li></ul><p><strong>染料褪色第一难题，灰平衡。</strong></p><p>染料墨水机型灰阶主要由CMY墨水混合，而CMY墨水褪色速率不一，这往往导致灰平衡破坏的非常快，DS6墨水短短3天，中性灰块的dE00就超过2.5。</p><p>但是灰平衡如果没有参照对比，不一定明显感知。</p><p><strong>染料C墨水褪色速率最快</strong></p><p>以色密度计算，C墨水褪色速率达到M墨水的2.5~4倍。如果无视灰平衡，把C墨水替换成耐候性更好的墨水，可以明显改善整体的耐候性。</p><p><strong>染料黑色墨水褪色发红</strong></p><p>不仅堆黑显眼，而且会参与到彩色增加色密度，跟C墨水一起劣化整体发红的趋势。干式彩扩黑色墨水褪色更偏向饱和度下降显旧，不至于那么显眼。</p><p>如果打算用染料墨水，最好做保护，覆膜、塑封、淋膜，保护后可以不避光。</p><p><strong>我更倾向爱普生机型，折腾空间大，详见后文墨水介绍。</strong></p><p>爱普生一般4万张左右打印头状态不佳，4万张之后基本要用最高质量加大喷墨量掩盖瑕疵。惠普对热发泡商用大幅面的建议是每色1.5L墨水换打印头，既4500~6000张左右A4幅面照片更换打印头。一般diy很难用掉那么多墨水。但是佳能打印头容易买还便宜，爱普生打印头坏了，不如买新机。</p><p>爱普生机壳不值钱，打印头值钱，尽量避免二手爱普生。爱普生的二手机，大都是商用的，打了几万张，干烂的机器，打印量写在主板上，看似打印量很少的机器，打印头有没有被掉包都不好说。商家收机器，打印量很少的好头，一般600~800可以卖给白墨烫画，UV打印之类的商家。跟着机壳一起卖的往往都是烂泥扶不上墙的打印头，基本上寿命都很短。</p><p>爱普生尽量买L8058、L8168新机，其他机型连续打厚纸可能不够稳定，L426X机壳打不了300克厚纸。</p><p>折腾墨水考虑L8058。原装墨水选L8168，耐候性显著强于L8058的原装墨水，色域也明显更广。</p><p><strong>L8168机型的走纸印在中间，避不开，L8058的走纸印在两边约1cm左右，可以避开</strong>。新出货的L8168有可能也改了，他们机壳很多设计都是通用的。</p><p><strong>佳能机型的走纸印，棘轮印要比爱普生好很多。</strong>不过覆PET哑膜后浅色基本感知不到，深色可能感知到。</p><p>佳能打印头寿命实在太短，只有用原装墨水考虑全新G580，1000出头就导入了灰色墨水。看似买机壳便宜，但是打印头相当于耗材，成本一下子就上去了。</p><p>E478机壳前身mg3080打不了厚纸。便宜机身考虑TS5380，跟这个机壳共用进纸组件的g5080等墨仓型号，有后进纸的，勉强能打厚纸。高质量彩打既选光泽照片纸，黑墨不喷墨，是CMY混合的黑色，相对不黑，而且因为CMY褪色速度不一样，打出来的黑色褪色更快更显眼。</p><p>二手TS5380，喷嘴折腾坏了买个新墨盒打洞就行，墨盒容量实在太小，最好配合三仓连供，按说明处理气压平衡，不然稳定性不太理想，不过总归没有墨仓稳定省心。</p><p>TS9020、TS8020、TS5080等几个二手机比较便宜，但能不能买到靠谱的打印头非常看运气，往往可能买来是好的，但连续打印会掉链子。</p><p><img src="https://s2.loli.net/2025/02/12/2NWyDfeOxgutMdq.jpg" alt="1.jpg"></p><p><img src="https://s2.loli.net/2025/02/12/XL5EamtwiMfs9PC.jpg" alt=".jpg"></p><h3 id="折腾墨水" tabindex="-1">折腾墨水： <a class="header-anchor" href="#折腾墨水" aria-label="Permalink to “折腾墨水：”">​</a></h3><ul><li>不打算用原装墨水可以买拆墨空机。</li></ul><p><strong>换任何墨水都必须校色。</strong><a href="https://zhuanlan.zhihu.com/p/441885301" target="_blank" rel="noreferrer">扫描仪校色打印机</a>；<a href="https://zhuanlan.zhihu.com/p/622264483" target="_blank" rel="noreferrer">校色仪校色打印机</a>；</p><p><strong>如果墨水更匹配喷墨程序，往往灰阶相对更中性，校色事半功倍。</strong>另色鬼056-RC专用龙纹，是我见过相对最匹配L8058机型喷墨程序的兼容墨水。</p><p>L8058的原装056墨水，耐候性相对014墨水有较大差距，但是价格却不便宜，我觉得有点小坑。</p><p><strong>买任何所谓原装墨水，拆机墨水，</strong>务必在爱普生或佳能官网能查到的店铺购买。真正卖拆机墨水的很不好搜到，而且倾向于整套一起卖。一搜就搜到，出货量很大，贼便宜的拆机墨水99%是假货。</p><ul><li>不在乎成本用干式彩扩机墨水，耐候性好很多。</li><li>兼容“耐光抗UV”染料避光或保护，见光无保护2~4周褪色。</li><li>C墨水褪色速率最快，用好的可以改善耐候性。</li></ul><p>保护既覆膜、塑封、淋膜，压在玻璃、亚克力等材料下也可以，保护后可以不避光，可能是光子激发反应时，还需要氧气参与反应。</p><p><strong>干式彩扩机墨水：</strong>L8168(014)，D580（墨瓶）；D700，D880，D1080（墨盒）。富士墨盒。浅色墨水（GY，LC，LM）可以<a href="https://zhuanlan.zhihu.com/p/27494317739" target="_blank" rel="noreferrer">自行稀释</a>。</p><p><strong>兼容染料色域不差，但是耐候性太差。必须买抗UV耐光染料，普通染料一天就变色。</strong></p><p>兼容“耐光抗UV”染料据我<a href="https://zhuanlan.zhihu.com/p/1911928560123351144" target="_blank" rel="noreferrer">测试</a>，所有品牌都没有质变，哪个便宜买哪个。适配056墨水以外的墨水通常色域明显更广，如适配大幅面或老型号R330，原装056可能为了耐候性限制了色域。深色墨水扩展色域，浅色墨水用适配机型的显色性匹配更好<strong>可能</strong>可以减少校色后色域容积的损失，但也不绝对。</p><p><a href="https://pan.baidu.com/s/1zSW2UQ2NfF16cG7zuKrDvg?pwd=bxzz" target="_blank" rel="noreferrer">我分享的校色ICC</a>。</p><p>偏重<strong>打印头寿命</strong>，我考虑色如丹色盐的染料，色如丹是爱普生供应商，色盐纯度应该可以。色如丹目前也建设了墨水产线，但不清楚哪些品牌贴牌。艺美佳同色如丹交叉持股，我推测艺美佳染料可能是色如丹的色盐。根据色如丹2022年的招股书，另色鬼、天威、墨库也都买过色如丹色盐。</p><p><strong>黑色墨水</strong>矬子里拔将军，另色鬼影像染料、鸿盛EverNew、天威R330影像级染料。另色鬼，鸿盛褪色发黄显旧，天威这款褪色发红不过色密度衰减慢点。</p><h3 id="兼容颜料" tabindex="-1">兼容颜料 <a class="header-anchor" href="#兼容颜料" aria-label="Permalink to “兼容颜料”">​</a></h3><p>兼容墨水没什么好折腾的，厂家没有做好墨水的市场空间，买大厂便宜的就行，如天威、传美讯、墨库（百度西）、鸿盛。</p><p>”珠海复旦创新研究院“团伙，发展下线”珠海云旦“已投产、”珠海中浆“在建产线。团伙专利CN114133792A（202111206014.5）《一种水性纳米颜料分散体》显示，其使用重氮盐偶合法对颜料颗粒表面进行改性，制得自分散颜料色浆的D50粒径在60nm左右，性能达到国际一流水平。</p><p>从技术原理推测该技术稳定性、抗老化性应该相当不俗，满足大部分需求，但不清楚改性是否对显色性有影响。所谓抗老化性就是放久了不堵头。</p><p>4色机、办公打印机买采购云丹色浆的传美讯、天威即可。纳思达旗下中润靖杰、格之格等马甲就有贴牌传美讯的产品。传美讯、天威缺点是原装是染料，他们好像也只做染料。只能买原装颜料机的，比如009。</p><p>目前中小墨水厂都在积极导入云旦色浆，用于影像输出，往往受烫金效应困扰。水性影像墨水的市场太小，厂家情愿生产喷墨印刷机的水性墨水，用云旦色浆稳定就行，没人开发影像墨水。</p><p><strong>颜料打照片纸优选P708机型，</strong>CMY混合的灰阶是烫金效应观感最怪的；L8168机型则算是能用。L8058的喷墨程序追求速度，上颜料墨水打照片纸状况频出，我<strong>猜测</strong>可能和打印头体质有关，因为反馈打印有小毛小病的很多，但是正常打的也有，不过商用量很大的话肯定是不够稳定的。L8058+颜料打艺术纸的话勉强吧，但也要空气湿度低，温度高，不能干太慢不然会有走纸印。</p><p>客观来说墨库·百度西，商用数码墨水中国出货量第一，杂质过滤合格，还便宜，<strong>性价比较高，但气味很大，更适合商用</strong>。墨库25年招股书显示，至少24年1~6月没有用过云旦色浆，墨库应该是自研磨。</p><p>墨仓机型干墨库颜料，不要用EP801；L8058、L18058有百度西EP818，L8168、L8188有EP816。</p><p>千万不要折腾鸿盛，不少老司机都铩羽而归。盛名之下,其实难副。</p><p>老经验：兼容颜料普遍色域只有原装颜料的70%。墨库的低温流动性较差，低温可能斜喷，断线。（注：墨库在过滤、抗老化性上已经算好的了）。我感觉珠海云旦的颜料色浆，可能无惧低温。</p><p>从另色鬼做056RC兼容染料比较用心来看，我<strong>推测</strong>另色鬼的影像兼容颜料可能还可以，可能是珠海云旦色浆，不排除是卡博特色浆的可能性，<strong>但不好说。</strong></p><ul><li><p>颜料墨水有烫金效应（反光泛白泛青铜色），观感不如染料自然，尤其是C墨水和CMY混和的灰阶。</p></li><li><p>原厂颜料可以改善反光泛青铜色，1~2￥/ml。</p></li><li><p>覆膜或塑封，注意热熔胶寿命不算理想，说不定还没褪色先开胶了。</p></li><li><p>颜料至少每周打1次可以是打印头检查图，太久不打可能堵死。</p></li><li><p>兼容颜料低温粘度变高，易斜喷。</p></li><li><p>热发泡尽量不要用颜料墨水，堵死没得修。爱普生打印头的堵头存在维修可能性，但不要因为能修就存在侥幸心理。</p></li><li><p>原装粗面黑在哑光纸上黑得多，但是不耐刮擦，不覆膜不建议用原装粗面黑墨水。</p></li></ul><p>相对爱普生10色机，4~6机型最大的短板是灰阶靠彩墨混合，P708不需要无关墨水增加色密度，靠对应颜色配合黑灰墨水就可以。而6色机型，往往需要无关墨水中和增加色密度，更容易因为同色异谱而产生色偏。即使都用光度计校色，如果对样张非常熟悉，还是看几眼能感知色准上的差距。</p><p>染料王就是L8168+014墨水，匹配喷墨程序。</p><p><a href="https://chnhi.github.io/lxzdy/ccc/%E8%89%B2%E5%BD%A9%E7%AE%A1%E7%90%86/%E6%89%93%E5%8D%B0%E6%9C%BA.html#%E9%BB%91%E7%99%BD%E6%BF%80%E5%85%89%C2%B7-%E5%AE%B6%E7%94%A8%C2%B7%E6%96%87%E6%A1%A3" target="_blank" rel="noreferrer">详细了解请参考【色彩管理-打印机】</a></p><h3 id="兼容影像颜料" tabindex="-1"><strong>兼容影像颜料</strong> <a class="header-anchor" href="#兼容影像颜料" aria-label="Permalink to “兼容影像颜料”">​</a></h3><p>我用天威788，只用浅色LC、LM、LK、LLK。深色CMYK、专色OGVR【微喷原装颜料墨盒抽墨】。</p><blockquote><p>微喷原装颜料墨盒抽墨参考： zhuanlan.zhihu.com/p/27494317739</p></blockquote><p>该浅色墨水据我测试（上海的2~3月，室温可能在15~20度，相对湿度约55左右）1个月不打不开机，再开机后，机器没有触发清洗，仅仅墨水气泵运转了一下，直接打打印头检查图，一针不断，应该说在抗老化性上性能是不错的。<strong>这样的行为是非常错误的，包括原装颜料墨水也请至少保证一周打一次。</strong></p><ul><li>深色用原装墨水，色密度更高，明显扩展色域，浅色用兼容水降低成本，观感影响较小。</li><li>专色用量少，如果用兼容墨水不扩展色域，没有任何理由不用原装抽墨。</li><li>Y尽量用原装，在CMY三色中Y比较浅，构成木桶效应的短板，如果厂家鲁莽加大黄色浓度则易堵头。Y用量是属于较大的。</li><li>K的话如果不AB对比就还好，一AB对比，兼容墨水马上露馅，感觉上黑位要差2~3级色阶。我推测跟树脂有关系，兼容颜料一样用碳黑，本身黑位应该不差。</li></ul><p>天威788直接找天威是不零售的，天威销售嫌量太少，不卖。只能找畅阳买贴牌，或问问淘宝”欣威耗材直销店“能不能帮忙进货。网上常卖的天威大幅面水性颜料瓶身上写的是NFE688，这款NFE788会贵一点，但不清楚有什么区别。这也正是为什么水性兼容颜料那么路边，稍微贵点的”高端“兼容颜料直接就卖不出去，没人进货。</p><p>少量天威788浅色可以联系我买抽墨，鱼同名“不晓自在”。原装墨盒CMY、PBK、MBK、V也可以抽，但推荐尽量自己买墨盒抽，一个是贵，再一个买家无从判断墨水到底是不是原装墨水。</p><p>天威专利CN112552746A显示，天威用了科莱恩有机颜料，科莱恩颜料据流言说，已经是兼容墨水厂家能弄到的比较好的颜料了。但不清楚天威是否用于实际零售的墨水，只能说赌一把，友商专利中科莱恩出镜率很低。天威保底应该是DIC色粉或云旦色浆，也能接受。该专利显示，天威改性色粉，用树脂+交联剂反应，使树脂在色粉表面成膜后再研磨制成色浆。</p><p>通篇根据专利，网友的测试推测，由于只能问市场销售人员，很多技术细节问不到，也问不到技术人员，大概率有错误，图一乐。</p><p>颜料是不溶解于墨水的悬浮物，靠分散形成均匀悬浮液，要实现分散，有两种方法：</p><p>1、用球磨机+氧化锆珠，研磨颜料、分散剂、溶剂，通过这种方法制得的色浆通常D50粒径约100nm出头，可能达到极限了。这种方法制得的分散剂颜料色浆，抗老化性不是很理想，甚至过个一年半载就可能会掉链子。</p><p>2、类似于珠海云旦，对颜料颗粒表面改性、接枝，制得自分散颜料色浆。D50粒径可以达到100nm以下，抗老化性更好。爱普生用界面聚合技术树脂胶囊化壳包覆颜料颗粒，可能也算是对颜料颗粒表面改性，或者说可能是双管齐下的。</p><p>过高粒径可能产生雾度，可能导致颜料墨水喷墨后看起来发灰，不通透。</p><p>采购的色浆有两个典型，卡博特、台湾纳米。卡博特所售色浆既自分散色浆，台湾纳米所售色浆是分散剂色浆。分散剂色浆在工业、纺织用途可能已经够用。</p><p>大墨水厂基本都是自研磨颜料色粉制得色浆，而不是采购色浆，只有小墨水厂采购色浆，采购色浆成本更高，自研磨固定投资相对大一点。</p><p>到底大墨水厂自研磨制备的是自分散颜料色浆，还是分散剂色浆，完全不得而知，参考专利也不太靠谱，因为搞不清楚实际售卖的到底是怎么回事，墨水厂专注于纺织、特种印刷，水性墨水非常路边，甚至可能懒得申请水性色浆专利。</p><p>如果咨询中小墨水厂，清一色都会说卡博特色浆，但如果进一步追问技术细节，他们的销售人员又是一问三不知，换言之，他们好像只知道卡博特这三个字，这就非常可疑。</p><p>假如真的是卡博特色浆，从理论上分析，还是相当不错的，尤其是搞不清楚大墨水厂的色浆工艺。但台湾纳米色浆的价格只有卡博特色浆的1/4~1/2，大陆产色浆可能还更便宜。到底用的是什么色浆，根本无从验证，反正我是不敢赌。想赌的话，可能可以试试另色鬼、艺美佳。</p><blockquote><p>言之凿凿用卡博特色浆的其中一家是东莞奥彩OCB，又是翻新打印头，又是仿冒原装墨水瓶身、包装，感觉这样的公司根本借不出充电宝啊。</p></blockquote><p>那么只能把目光放到大墨水厂。传美讯专注OEM零售，墨库花小钱办大事，绝对是合格的产品，但不一定是最好的产品。</p><p>大墨水厂只剩下天威、鸿盛。鸿盛鸿彩6据网友测试，墨水在过滤时过滤出了杂质，专色还是CMY勾兑，不扩展色域。我推测专色的销量可能撑不起研磨产线启动，干脆马虎了事，但实际上应该是可以买卡博特、科莱恩、东洋的专色色浆，不需要开动研磨产线，换言之并不存在技术上的困难，只存在用心与否的困难，只存在成本上的困难。</p><p>鸿盛吹嘘的颜料纳米胶囊化，从鸿盛水性专利来看可能是含树脂研磨。鸿盛通过技术手段预处理颜料表面使其亲水，或在搅拌过程中添加交联剂进行反应的技术集中于纺织墨水专利。</p><h3 id="纸" tabindex="-1">纸 <a class="header-anchor" href="#纸" aria-label="Permalink to “纸”">​</a></h3><ul><li><strong>印刷厂</strong>俗称<strong>铜版纸</strong>的纸张，准确来说是 印刷涂布纸coated art paper。</li></ul><p>没有喷墨涂层，喷墨打印机要用铜版纸颜料墨水（快干颜料墨水），最好改装加热装置。墨水掺了溶剂有腐蚀性，不仅影响打印头寿命，而且低温下粘度会变高，打印容易斜喷或断线。</p><ul><li>喷墨用的” <strong>高光铜版纸</strong> “，准确来说是“喷墨铜版纸”inkjet coated paper。</li></ul><p>有喷墨涂层，可以吸收更多墨水增加色密度，色彩表现力相当不错。但是：</p><ol><li>涂层也计入克重，相同克重下更薄更软。</li><li><strong>反光能感知走纸印和棘轮印，两张卡摩擦有白痕，必须要保护。</strong></li><li>覆PET哑膜可以改善走纸印和棘轮印。</li><li>最好用染料墨水，颜料墨水的烫金效应会导致反光观感怪异。</li></ol><ul><li>”<strong>白卡纸</strong>“。有350g，400g。</li></ul><p>白卡纸克重就是纯纸，最硬挺。但是靠纸基吸墨，色密度<strong>严重受限</strong>，影响表现力，由于墨水被纸张吸收，会泛纸张本色，显得色密度不够。颜料要原装粗面黑才比较黑，但是不耐刮擦，手一摸就变黑。</p><ul><li>哑光喷墨铜版纸，matte inkjet coated paper。</li></ul><p>所谓“哑光铜版纸”有两类，一类实质就是白卡纸。另一类有涂层。有涂层的我买到过两种：</p><p>1、骏马纸业代工，很多小牌子的所谓哑光铜版纸就是贴牌。这个纸我认为可以称为“丝光彩喷纸”。说是哑光，实际上还是有轻微的反光。相对高光铜版纸，走纸印和棘轮印有很大的改善，基本要反光细品才能感知到有走纸印。但是表现力相对高光铜版纸要稍差些。</p><p><strong>这个纸经常本身涂层上就有斑驳的痕迹，覆膜后会很明显。</strong></p><p>必须覆膜，不覆膜切割后，切口处涂层会有皲裂。覆膜后染料颜料都可以用。</p><p>2、我称为”哑光彩喷纸“，有涂层但是不会反光，表现力相对“丝光彩喷纸”要差。我买到过力武的“哑光铜版纸”是这类。</p><p>走纸印和棘轮印相对“丝光彩喷纸”改善一点，基本要浅色部分反光细品才能感知。搭配颜料墨水，黑色墨水堆积的地方会有反光，其他地方又没有反光，反光就会有一点斑驳。这款纸如果天气潮湿，颜料墨水干的慢了，会有明显走纸印。</p><ul><li>增强粗面艺术纸</li></ul><p>走纸印和棘轮印相对哑光铜版纸还要进一步改善，不怎么能感知到，但是由于是涂层和纸基一起吸墨，所以精度锐度相对会差一些，成本还高。颜料要原装粗面黑才比较黑，但是不耐刮擦，手一摸就变黑，不然会泛纸白。</p><p>搭配颜料墨水没有烫金效应，观感比较“自然”温暖，但是要写实的作品才能体现，自印卡基本没有。</p><ul><li><strong>RC细绒相纸</strong>搭配颜料墨水有非常强的表现力，但又软又薄，可以考虑白条卡或塑封。</li></ul><p>RC相纸色域最广，广很多。不易感知走纸印，细品可能感知棘轮印。</p><ul><li>莱妮纹 珠光纸，布纹效果。</li><li>diy局部镭射闪卡请参考<a href="https://space.bilibili.com/21376007" target="_blank" rel="noreferrer">白羽ことり</a>的<a href="https://www.bilibili.com/read/cv11111496/" target="_blank" rel="noreferrer">分享</a>。其用到的镭射透明不干胶，透明pet等可以打颜料墨水。</li></ul><p><a href="https://chnhi.github.io/lxzdy/ccc/%E8%89%B2%E5%BD%A9%E7%AE%A1%E7%90%86/%E6%89%93%E5%8D%B0%E6%9C%BA.html#%E5%96%B7%E5%A2%A8%E4%B8%8E%E7%89%B9%E6%AE%8A%E7%BA%B8" target="_blank" rel="noreferrer">简单介绍工业用墨水请参考。</a></p><blockquote><p>工业墨水：弱溶剂墨水，乳胶墨水，涂料墨水（DTF烫画墨水），UV墨水等，腐蚀打印介质或通过不同原理固化成膜，极易堵头，还具有强腐蚀性，<strong>非工业打印头寿命按天计算。</strong></p></blockquote><h2 id="diy-pvc卡" tabindex="-1">DIY-PVC卡 <a class="header-anchor" href="#diy-pvc卡" aria-label="Permalink to “DIY-PVC卡”">​</a></h2><p>DIY可行的PVC卡有两种，一种是PVC免层压，另一种是喷墨PVC白卡。</p><p><strong>PVC免层压</strong>是PVC卡上涂有热熔胶，打印在PET透明膜上（有喷墨涂层）然后过塑封机，把PET透明膜和PVC卡胶合，然后用重型冲卡器冲卡。热熔胶寿命不长会脱胶，甚至刚做完就起泡。</p><p>L8058机型有PVC证卡托架，可以打印在PVC白卡上，必须是<strong>喷墨PVC白卡</strong>，涂布了喷墨涂层。缺点是只有86x54尺寸。最好用颜料墨水。</p><p>88x63尺寸我估计应该是可以打的，只不过喷墨白卡和托架都要定制，不知道在哪定制托架。</p><p>L8168机型有一个后部进纸槽，把屁股掀开可以平行进纸。网上搜 L8168 打印证卡看看视频，自己3d打印一个类似的托盘，自己在InDesign软件微调出适配的模板文件。</p><h2 id="测试不适合diy的" tabindex="-1">测试不适合diy的 <a class="header-anchor" href="#测试不适合diy的" aria-label="Permalink to “测试不适合diy的”">​</a></h2><h3 id="切卡-1" tabindex="-1">切卡 <a class="header-anchor" href="#切卡-1" aria-label="Permalink to “切卡”">​</a></h3><p>  手动模切机配刀模，挨得太近压力不够会撕扯打印面，而且免不了会有一点位移刮伤打印面，感觉电动模切机也够呛。</p><p>  刻字机，要打标记点给机器巡边，A4只能切6张卡，而且机器不能校正角度偏斜，要自己对齐摆放，会有刀口毛刺，而且切割要有垫板保护刀头，垫板有粘性，所以必须要给纸覆膜，或本身就是不干胶有背纸，不然打印面会粘在垫板上。</p><h3 id="保护" tabindex="-1">保护 <a class="header-anchor" href="#保护" aria-label="Permalink to “保护”">​</a></h3><ul><li>双面RC细绒相纸+水性光油。</li></ul><p>  水光油用丝印尖口刮刀在RC相纸的打印面刷一遍，不需要丝印网板，就能实现不错的光泽度和顺滑的手感。裸卡重叠在一起相互摩擦，分离非常顺滑，但是相对原卡明显薄软很多。RC绒面观感更有质感，但与原卡明显不同。</p><p><strong>但手动涂布免不了出现瑕疵。</strong></p><blockquote><p>RC相纸表面有一层淋膜，防水，水光油不会马上成膜，而且是孔隙结构，用水光油中的树脂颗粒填充孔隙后，光泽度好，手感顺滑。铜版纸是一层蜡，手动涂布不够均匀，成膜效果不佳。</p></blockquote><ul><li>uv光油</li></ul><p>  uv打印机打光油，手感不润。手动涂布光油墨水会有油性物质渗进纸张，不清楚是溶剂还是稀释剂之类的成分。</p><p>  UVC光油，丝印尖口刮刀不需要丝网，可以薄薄的挂一层，要用高压汞灯，对皮肤，人眼都有伤害，有刺鼻的刺激性气味。LED-UV灯，365或395nm波长的不行。</p><p>  原卡一般是过水光油，硬度高，手感顺滑，还会压光（磨光）磨薄涂层。UV光油硬度差很多，顺滑程度明显不如。</p><blockquote><p>橡胶滚筒瑕疵多一些，较厚，明显感知。</p></blockquote><blockquote><p>丝印网板缺点是没有喷枪清洗不干净，效果比滚筒好，但是从网板拿下来的时候会有痕迹。</p></blockquote><ul><li>亮色墨水</li></ul><p>  爱普生P408和佳能pro-300有亮光色墨水通道，但都只是薄薄的覆一层，不能在哑面纸上实现光泽，但是可以实现卡变得很顺滑。</p><ul><li>水性光油</li></ul><p>  工业用的水性光油，线棒涂布不能流平有纹路，丝网会黏住，塑封机会留下胶辊上的纹理，还会黏到灰尘。喷漆枪要喷的厚一点，但还是免不了会有麻子，往往喷涂量过大，导致纸张吸水，干燥后纸张会翘曲变形。橡胶滚筒不能均匀涂抹。</p><blockquote><p>铜版纸只有表面的蜡有一定防水性能，纸芯不防水。</p></blockquote><ul><li>油墨光油</li></ul><p>  油墨光油，黄黄的，不是很透。橡胶滚筒效果凑合，太厚，干的太慢，要几十个小时，免不了会沾到灰尘。油墨要用天拿水清洗，用水冲没用。油墨本身味道较淡，但是天拿水味道相当大，相当上头。</p>`,223)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};